    int location;
    int indices[509];
    int keys[509];
    bool is_leaf;
    int num_keys;
} knode;

kernel void findK(    long maxheight,
                      global const knode *knodes,
                      long knodes_elem,
                      global const record *records,
                      global long *currKnode,
                      global long *offset,
                      global const int *keys,
                      global record *ans)
{
    int bid = get_group_id(0);
    int thid = get_local_id(0);
    int threadsPerBlock = get_local_size(0);

    int i;

    for(i = 0; i < maxheight; i++){
        for(thid = 0; thid < threadsPerBlock; thid++){
            if((knodes[currKnode[bid]].keys[thid] <= keys[bid]) && 
               (knodes[currKnode[bid]].keys[thid+1] > keys[bid])){
                if(knodes[offset[bid]].indices[thid] < knodes_elem){
                    offset[bid] = knodes[offset[bid]].indices[thid];
                }
            }
        }
        currKnode[bid] = offset[bid];
    }

    for(thid = 0; thid < threadsPerBlock; thid++){
        if(knodes[currKnode[bid]].keys[thid] == keys[bid]){
            ans[bid].value = records[knodes[currKnode[bid]].indices[thid]].value;
        }
    }
}

